import{_ as a,o as e,c as s,ag as i}from"./chunks/framework.Culc7SYV.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"Installation.md","filePath":"Installation.md","lastUpdated":1773806339000}'),l={name:"Installation.md"};function n(o,t,r,d,h,p){return e(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="install-paths" tabindex="-1">Install Paths <a class="header-anchor" href="#install-paths" aria-label="Permalink to &quot;Install Paths&quot;">​</a></h2><p>Use one of the following methods.</p><h2 id="brat-method" tabindex="-1">BRAT Method <a class="header-anchor" href="#brat-method" aria-label="Permalink to &quot;BRAT Method&quot;">​</a></h2><ol><li>Install <a href="https://github.com/TfTHacker/obsidian42-brat" target="_blank" rel="noreferrer">BRAT</a> from Obsidian Community Plugins.</li><li>In BRAT settings, add <code>ctrlaltwill/LearnKit</code>.</li><li>BRAT installs LearnKit and keeps it updated.</li></ol><h2 id="release-method" tabindex="-1">Release Method <a class="header-anchor" href="#release-method" aria-label="Permalink to &quot;Release Method&quot;">​</a></h2><ol><li><p>Open <a href="https://github.com/ctrlaltwill/LearnKit/releases" target="_blank" rel="noreferrer">Releases</a> and download the latest release.</p></li><li><p>Copy <code>main.js</code>, <code>styles.css</code>, and <code>manifest.json</code> into:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;Your Vault&gt;/.obsidian/plugins/sprout/</span></span></code></pre></div><p>Note: the plugin directory is currently named <code>sprout</code> for compatibility.</p></li><li><p>Restart Obsidian, then enable <strong>LearnKit</strong> in <strong>Settings → Community Plugins</strong>.</p></li></ol><h2 id="source-method" tabindex="-1">Source Method <a class="header-anchor" href="#source-method" aria-label="Permalink to &quot;Source Method&quot;">​</a></h2><p>Requires <a href="https://nodejs.org/" target="_blank" rel="noreferrer">Node.js</a> 18+.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/ctrlaltwill/LearnKit.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> LearnKit</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>The built plugin files are output to <code>dist/</code>. Copy or symlink that folder into your vault:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">pwd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)/dist&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;Your Vault&gt;/.obsidian/plugins/sprout&quot;</span></span></code></pre></div><p>Note: the symlink target keeps the <code>sprout</code> directory name for compatibility.</p><p>Restart Obsidian -&gt; Settings -&gt; Community Plugins -&gt; Enable LearnKit.</p><h2 id="dev-scripts" tabindex="-1">Dev Scripts <a class="header-anchor" href="#dev-scripts" aria-label="Permalink to &quot;Dev Scripts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Script</th><th>What it does</th></tr></thead><tbody><tr><td><code>npm run dev</code></td><td>Watch mode — rebuilds JS + CSS on every file change</td></tr><tr><td><code>npm run build</code></td><td>Production build (minified JS + CSS), copies manifest into <code>dist/</code></td></tr></tbody></table><h2 id="next-step" tabindex="-1">Next Step <a class="header-anchor" href="#next-step" aria-label="Permalink to &quot;Next Step&quot;">​</a></h2><ul><li><a href="./Syncing">Syncing</a></li><li><a href="./Flashcards">Flashcards</a></li></ul>`,19)])])}const k=a(l,[["render",n]]);export{u as __pageData,k as default};
